if(!root)return;
var D={
  prod:parseFloat(root.dataset.prod)||0,
  cons:parseFloat(root.dataset.cons)||0,
  soc:parseFloat(root.dataset.soc)||0,
  bat:parseFloat(root.dataset.bat)||0,
  meter:parseFloat(root.dataset.meter)||0,
  charge:parseFloat(root.dataset.charge)||0,
  carConn:parseFloat(root.dataset.carConn)||0,
  dCons:parseFloat(root.dataset.dCons)||0,
  dGen:parseFloat(root.dataset.dGen)||0,
  mCons:parseFloat(root.dataset.mCons)||0,
  mGen:parseFloat(root.dataset.mGen)||0,
  selfSuf:parseFloat(root.dataset.selfSuf)||0,
  vbCharge:parseFloat(root.dataset.vbCharge)||0,
  vbProd:parseFloat(root.dataset.vbProd)||0,
  vbCons:parseFloat(root.dataset.vbCons)||0,
  vbPct:parseFloat(root.dataset.vbPct)||0,
  batHrs:parseFloat(root.dataset.batHrs)||0,
  batMins:parseFloat(root.dataset.batMins)||0,
  batChgHrs:parseFloat(root.dataset.batChgHrs)||0,
