};

function setBars(cId,gId,gcId,ggId,c,g){
  var mx=Math.max(c,g,0.1);
  var cb=document.getElementById(cId),gb=document.getElementById(gId);
  var gcG=document.getElementById(gcId),ggG=document.getElementById(ggId);
  if(cb)cb.style.width=(c/mx*100)+"%";
  if(gb)gb.style.width=(g/mx*100)+"%";
  if(gcG)gcG.style.left=(c/mx*100-1)+"%";
  if(ggG)ggG.style.left=(g/mx*100-1)+"%";
}
setBars("pf6-bar-dc","pf6-bar-dg","pf6-glow-dc","pf6-glow-dg",D.dCons,D.dGen);
setBars("pf6-bar-mc","pf6-bar-mg","pf6-glow-mc","pf6-glow-mg",D.mCons,D.mGen);

