function rr(c,x,y,w,h,r){c.beginPath();c.moveTo(x+r,y);c.lineTo(x+w-r,y);c.quadraticCurveTo(x+w,y,x+w,y+r);c.lineTo(x+w,y+h-r);c.quadraticCurveTo(x+w,y+h,x+w-r,y+h);c.lineTo(x+r,y+h);c.quadraticCurveTo(x,y+h,x,y+h-r);c.lineTo(x,y+r);c.quadraticCurveTo(x,y,x+r,y);c.closePath();}

// ── SOLAR (150x105) ──
function drawSolar(ctx){
  var kw=D.prod,maxKw=10,R=Math.min(kw/maxKw,1),t=Date.now();
  var cr,cg,cb,ch;
  if(kw<2){cr=100;cg=220;cb=100;ch="#64dc64";}
  else if(kw<4){cr=30;cg=140;cb=50;ch="#1e8c32";}
  else if(kw<6){cr=100;cg=190;cb=255;ch="#64beff";}
  else{cr=40;cg=100;cb=220;ch="#2864dc";}
  var sa=0.6+R*0.4,rp=0.7+Math.sin(t/400)*0.3,rl=(6+R*10)*rp;
  var cx=75,cy=35;
  ctx.clearRect(0,0,150,125);
  ctx.save();ctx.translate(6,0);ctx.scale(0.92,0.92);
  var g1=ctx.createRadialGradient(cx,cy,0,cx,cy,35+R*20);
  g1.addColorStop(0,"rgba(255,180,30,"+(0.12+R*0.18)+")");g1.addColorStop(1,"rgba(255,180,30,0)");
  ctx.fillStyle=g1;ctx.beginPath();ctx.arc(cx,cy,55+R*20,0,Math.PI*2);ctx.fill();
  var g2=ctx.createRadialGradient(cx,cy,0,cx,cy,20+R*10);
  g2.addColorStop(0,"rgba(255,200,50,"+(0.25+R*0.35)+")");g2.addColorStop(1,"rgba(255,200,50,0)");
  ctx.fillStyle=g2;ctx.beginPath();ctx.arc(cx,cy,30+R*10,0,Math.PI*2);ctx.fill();
  ctx.beginPath();ctx.arc(cx,cy,10,0,Math.PI*2);ctx.fillStyle="rgba(255,200,30,"+sa+")";ctx.fill();
  ctx.strokeStyle="rgba(255,210,50,"+(0.3+R*0.5)+")";ctx.lineWidth=2;ctx.lineCap="round";
  for(var i=0;i<8;i++){var a=i/8*Math.PI*2;ctx.beginPath();ctx.moveTo(cx+Math.cos(a)*12,cy+Math.sin(a)*12);ctx.lineTo(cx+Math.cos(a)*(12+rl),cy+Math.sin(a)*(12+rl));ctx.stroke();}
  ctx.lineCap="butt";
  ctx.fillStyle="#1a3a5c";ctx.fillRect(20,70,110,22);
  ctx.strokeStyle="#2a5a8c";ctx.lineWidth=0.3;
  [0,22,44,66,88,110].forEach(function(dx){ctx.beginPath();ctx.moveTo(20+dx,70);ctx.lineTo(20+dx,92);ctx.stroke();});
  [0,7,14,22].forEach(function(dy){ctx.beginPath();ctx.moveTo(20,70+dy);ctx.lineTo(130,70+dy);ctx.stroke();});
  ctx.lineWidth=0.5;ctx.strokeRect(20,70,110,22);
  ctx.fillStyle="rgba("+cr+","+cg+","+cb+","+(0.1+R*0.25)+")";ctx.fillRect(20,70,110,22);
  ctx.fillStyle=ch;ctx.font="800 26px system-ui,sans-serif";ctx.textAlign="center";ctx.textBaseline="middle";
  ctx.fillText(kw.toFixed(2)+" kW",75,104);


  ctx.restore();
}

// ── HOUSE (150x105) ──
function drawHouse(ctx){
  var kw=D.cons,maxKw=8,R=Math.min(kw/maxKw,1),t=Date.now();
  var hue=R<0.4?120:R<0.7?40:0;
  var breathe=Math.sin(t/(1000-R*600))*0.15+0.85;
  var ga=(0.3+R*0.7)*breathe;
  var nLit=Math.ceil(R*4);
  ctx.clearRect(0,0,150,125);
  ctx.save();ctx.translate(6,0);ctx.scale(0.92,0.92);
  ctx.save();ctx.shadowColor="hsla("+hue+",80%,45%,"+(ga*0.5)+")";ctx.shadowBlur=18;
  ctx.fillStyle="hsla("+hue+",80%,45%,"+(ga*0.5)+")";ctx.fillRect(10,12,130,85);ctx.restore();
  ctx.save();ctx.shadowColor="hsla("+hue+",90%,55%,"+ga+")";ctx.shadowBlur=10;
  ctx.fillStyle="hsla("+hue+",90%,55%,"+ga+")";ctx.fillRect(25,27,100,65);ctx.restore();
  ctx.beginPath();ctx.moveTo(75,5);ctx.lineTo(18,38);ctx.lineTo(132,38);ctx.closePath();
  ctx.fillStyle="#2a2a2a";ctx.fill();ctx.strokeStyle="#444";ctx.lineWidth=1.5;ctx.stroke();
  ctx.fillStyle="#333";ctx.fillRect(100,13,12,22);ctx.strokeStyle="#444";ctx.lineWidth=1;ctx.strokeRect(100,13,12,22);
  ctx.fillStyle="#1a1a1a";ctx.fillRect(28,38,94,52);ctx.strokeStyle="#333";ctx.lineWidth=1;ctx.strokeRect(28,38,94,52);
  ctx.fillStyle="hsla("+hue+",60%,40%,"+(R*0.08)+")";ctx.fillRect(28,38,94,52);
  rr(ctx,64,73,22,22,2);ctx.fillStyle="#222";ctx.fill();ctx.strokeStyle="#444";ctx.lineWidth=1;ctx.stroke();
  ctx.beginPath();ctx.arc(81,85,1.5,0,Math.PI*2);ctx.fillStyle="#666";ctx.fill();
  var wp=[[38,48],[78,48],[38,68],[78,68]];
  for(var i=0;i<4;i++){
    var wx=wp[i][0],wy=wp[i][1],lit=i<nLit;
    var fl=lit?0.7+Math.sin(t/125+i*2.5)*0.2:0;
    if(lit){ctx.save();ctx.shadowColor="hsla("+hue+",90%,65%,"+(fl*0.35)+")";ctx.shadowBlur=4;
    ctx.fillStyle="hsla("+hue+",90%,65%,"+(fl*0.35)+")";ctx.fillRect(wx-3,wy-3,24,22);ctx.restore();}
    rr(ctx,wx,wy,18,16,1);ctx.fillStyle=lit?"hsla("+hue+",90%,65%,"+fl+")":"#111";ctx.fill();
    ctx.strokeStyle="#444";ctx.lineWidth=0.8;ctx.stroke();
    var ck=lit?"hsla("+hue+",60%,40%,1)":"#333";ctx.strokeStyle=ck;ctx.lineWidth=0.5;
    ctx.beginPath();ctx.moveTo(wx+9,wy);ctx.lineTo(wx+9,wy+16);ctx.stroke();
    ctx.beginPath();ctx.moveTo(wx,wy+8);ctx.lineTo(wx+18,wy+8);ctx.stroke();
  }
  ctx.fillStyle="hsl("+hue+",80%,55%)";ctx.font="800 26px system-ui,sans-serif";
  ctx.textAlign="center";ctx.textBaseline="middle";ctx.fillText(kw.toFixed(2)+" kW",75,104);


  ctx.restore();
}

// ── GRID (180x67, compact — now in row 3) ──
function drawGrid(ctx){
  var kw=D.meter,maxKw=5,t=Date.now();
  var balanced=Math.abs(kw)<0.25,importing=kw<0;
  var mag=Math.min(Math.abs(kw)/maxKw,1);
  var color=balanced?"#50a0ff":importing?"#ff5050":"#50ff78";
  var midY=35,dir=importing?1:-1;
  ctx.clearRect(0,0,180,67);
  ctx.save();ctx.translate(12.6,0);ctx.scale(0.86,0.86);
  [28,152].forEach(function(x){
    ctx.strokeStyle="#444";ctx.lineWidth=2;
    ctx.beginPath();ctx.moveTo(x-6,midY+22);ctx.lineTo(x,midY-18);ctx.stroke();
    ctx.beginPath();ctx.moveTo(x+6,midY+22);ctx.lineTo(x,midY-18);ctx.stroke();
    ctx.lineWidth=1.5;
    ctx.beginPath();ctx.moveTo(x-10,midY-4);ctx.lineTo(x+10,midY-4);ctx.stroke();
  });
  ctx.beginPath();ctx.moveTo(10,midY);ctx.lineTo(170,midY);ctx.strokeStyle="#333";ctx.lineWidth=2.5;ctx.stroke();
  if(!balanced){
    ctx.save();ctx.beginPath();ctx.moveTo(10,midY);ctx.lineTo(170,midY);
    ctx.strokeStyle=color;ctx.lineWidth=4+mag*4;ctx.globalAlpha=0.4+mag*0.5;
    ctx.setLineDash([6+mag*8,8-mag*4]);ctx.lineDashOffset=-(t/30*dir);
    ctx.lineCap="round";ctx.stroke();ctx.setLineDash([]);ctx.globalAlpha=1;ctx.lineCap="butt";ctx.restore();
  }
  if(balanced){
    var gr=12+Math.sin(t/360)*3,gA=0.15+Math.sin(t/360)*0.1;
    var bg=ctx.createRadialGradient(90,midY,0,90,midY,gr);
    bg.addColorStop(0,"rgba(80,160,255,"+Math.max(0,gA)+")");bg.addColorStop(1,"rgba(80,160,255,0)");
    ctx.fillStyle=bg;ctx.beginPath();ctx.arc(90,midY,gr,0,Math.PI*2);ctx.fill();
  }
  if(!balanced){
    var aOff=Math.sin(t/240)*12*dir,ax=90+aOff;
    ctx.beginPath();
    if(importing){ctx.moveTo(ax+12,midY);ctx.lineTo(ax-6,midY-9);ctx.lineTo(ax-6,midY+9);}
    else{ctx.moveTo(ax-12,midY);ctx.lineTo(ax+6,midY-9);ctx.lineTo(ax+6,midY+9);}
    ctx.closePath();ctx.fillStyle=color;ctx.globalAlpha=0.8;ctx.fill();ctx.globalAlpha=1;
  }
  ctx.fillStyle="#666";ctx.font="10px sans-serif";
  ctx.textAlign="left";ctx.fillText("GRID",15,midY+28);
  ctx.textAlign="right";ctx.fillText("HOME",165,midY+28);


  ctx.restore();
}

// ── BATTERY (150x105) ──
function drawBattery(ctx){
  var pct=D.soc,chg=D.bat,t=Date.now();
  var charging=chg<-0.25,discharging=chg>0.25,idle=!charging&&!discharging;
  var active=!idle,intensity=Math.min(Math.abs(chg)/5,1);
  var hue=pct<20?0:pct<50?40:120;
  var stateColor=idle?"#666":charging?"#44ee44":"#ff4444";
  var borderColor=idle?"#555":stateColor;
  var pctColor=pct<20?"#ff4444":pct<50?"#ffaa00":"#44dd44";
  var bx=10,by=20,bw=110,bh=55;
  var fillW=Math.max(0,(pct/100)*(bw-4));
  var pulseAlpha=active?0.2+Math.sin(t/320)*0.15:0;
  var boltAlpha=idle?0.25:0.5+Math.sin(t/240)*0.3;
  var boltW=idle?2:3+intensity*6;
  ctx.clearRect(0,0,150,125);
  ctx.save();ctx.translate(6,0);ctx.scale(0.92,0.92);
  if(active){
    ctx.save();ctx.shadowColor=borderColor;ctx.shadowBlur=5;
    rr(ctx,bx-4,by-4,bw+8,bh+8,6);ctx.strokeStyle=borderColor;ctx.lineWidth=3;
    ctx.globalAlpha=pulseAlpha;ctx.stroke();ctx.globalAlpha=1;ctx.restore();
  }
  rr(ctx,bx+bw,by+18,11,24,2);ctx.fillStyle=active?borderColor:"#444";
  if(active){ctx.globalAlpha=0.6+Math.sin(t/320)*0.3;}ctx.fill();ctx.globalAlpha=1;
  rr(ctx,bx,by,bw,bh,5);ctx.fillStyle="#111";ctx.fill();ctx.strokeStyle=borderColor;ctx.lineWidth=2.5;ctx.stroke();
  if(fillW>0){
    var fg=ctx.createLinearGradient(bx+2,0,bx+2+fillW,0);
    fg.addColorStop(0,"hsla("+hue+",80%,55%,0.8)");fg.addColorStop(1,"hsla("+hue+",80%,45%,0.95)");
    ctx.save();rr(ctx,bx+2,by+2,bw-4,bh-4,3);ctx.clip();
    ctx.fillStyle=fg;ctx.fillRect(bx+2,by+2,fillW,bh-4);ctx.restore();
  }
  ctx.save();ctx.shadowColor="rgba(0,0,0,0.9)";ctx.shadowBlur=6;
  ctx.fillStyle=pctColor;ctx.font="800 28px system-ui,sans-serif";
  ctx.textAlign="center";ctx.textBaseline="middle";
  ctx.fillText(Math.round(pct)+"%",bx+bw/2,by+bh/2-1);ctx.restore();
  ctx.save();ctx.globalAlpha=boltAlpha;
  ctx.beginPath();ctx.moveTo(70,24);ctx.lineTo(56,50);ctx.lineTo(66,50);ctx.lineTo(58,70);
  ctx.lineTo(80,44);ctx.lineTo(70,44);ctx.lineTo(80,24);ctx.closePath();
  ctx.fillStyle=stateColor;ctx.globalAlpha=boltAlpha*(idle?0.4:0.7);ctx.fill();
  ctx.strokeStyle=stateColor;ctx.lineWidth=boltW;ctx.lineJoin="round";ctx.lineCap="round";
  ctx.globalAlpha=boltAlpha;ctx.stroke();ctx.restore();
  ctx.fillStyle=stateColor;ctx.font="800 26px system-ui,sans-serif";
  ctx.textAlign="center";ctx.textBaseline="middle";
  ctx.fillText((chg>0?"+":"")+chg.toFixed(2)+" kW",bx+bw/2,by+bh+18);
  // Time remaining — discharge OR charge
  var ttlH=D.batHrs,ttlM=D.batMins;
  var tchH=D.batChgHrs,tchM=D.batChgMins;
  if(discharging&&(ttlH>0||ttlM>0)){
    var ttlTotal=ttlH+ttlM/60;
    var ttlColor=ttlTotal>4?"#44dd44":ttlTotal>1?"#ffaa00":"#ff4444";
    ctx.fillStyle=ttlColor;ctx.font="700 20px system-ui,sans-serif";
    ctx.textAlign="center";ctx.textBaseline="middle";
    ctx.fillText("~"+ttlH+"h "+ttlM+"m",bx+bw/2,by+bh+40);
  }else if(charging&&(tchH>0||tchM>0)){
    ctx.fillStyle="#44dd44";ctx.font="700 20px system-ui,sans-serif";
    ctx.textAlign="center";ctx.textBaseline="middle";
    ctx.fillText("~"+tchH+"h "+tchM+"m",bx+bw/2,by+bh+40);
  }


  ctx.restore();
}

// ── WALLBOX (150x105) ──
function drawWallbox(ctx){
  var kw=D.charge,maxKw=11,t=Date.now();
  var charging=kw>0&&D.carConn>0;
  var connected=D.carConn>0;
  var ratio=Math.min(kw/maxKw,1);
  var hue=charging?145:35;
  var stateColor=charging?"#00cc66":connected?"#f90":"#444";
  var breathe=charging?Math.sin(t/(800-ratio*400))*0.12+0.88:1;
  var nBars=charging?Math.ceil(ratio*4):0;
  ctx.clearRect(0,0,150,125);
  ctx.save();ctx.translate(6,0);ctx.scale(0.92,0.92);
  // Charger box
  rr(ctx,10,22,32,48,4);ctx.fillStyle="#1a1a2e";ctx.fill();
  ctx.strokeStyle=stateColor;ctx.lineWidth=1.5;ctx.globalAlpha=charging?breathe:0.6;ctx.stroke();ctx.globalAlpha=1;
  // Charger post
  ctx.fillStyle="#1a1a2e";ctx.fillRect(21,70,10,14);
  // Screen
  rr(ctx,16,28,20,10,1);
  ctx.fillStyle=charging?"rgba(0,200,80,"+(0.35*breathe)+")":connected?"rgba(255,160,0,0.15)":"rgba(60,60,60,0.2)";ctx.fill();
  // Status LED
  ctx.beginPath();ctx.arc(26,46,3,0,Math.PI*2);
  ctx.fillStyle=charging?"rgba(0,220,100,"+(0.6*breathe)+")":connected?"rgba(255,160,0,0.4)":"rgba(80,80,80,0.3)";ctx.fill();
  // Cable
  ctx.beginPath();ctx.moveTo(42,42);ctx.quadraticCurveTo(62,78,86,62);
  ctx.strokeStyle=stateColor;ctx.lineWidth=charging?3:2;ctx.lineCap="round";
  ctx.globalAlpha=charging?breathe:0.5;ctx.stroke();ctx.globalAlpha=1;ctx.lineCap="butt";
  // Car body
  ctx.beginPath();ctx.moveTo(78,55);ctx.lineTo(84,42);ctx.lineTo(136,42);ctx.lineTo(142,55);
  ctx.lineTo(144,68);ctx.lineTo(76,68);ctx.closePath();ctx.fillStyle="#1a1a2e";ctx.fill();
  ctx.strokeStyle=charging?stateColor:"#444";ctx.lineWidth=1.5;ctx.globalAlpha=charging?0.7*breathe:0.6;ctx.stroke();ctx.globalAlpha=1;
  // Windshield
  ctx.beginPath();ctx.moveTo(92,42);ctx.lineTo(98,30);ctx.lineTo(126,30);ctx.lineTo(132,42);ctx.closePath();
  ctx.fillStyle="#111";ctx.fill();ctx.strokeStyle=charging?"rgba(0,140,60,0.3)":"#333";ctx.lineWidth=1;ctx.stroke();
  // Wheels
  [92,132].forEach(function(wx){
    ctx.beginPath();ctx.arc(wx,70,6,0,Math.PI*2);ctx.fillStyle="#111";ctx.fill();
    ctx.strokeStyle="#444";ctx.lineWidth=1.5;ctx.stroke();
    ctx.beginPath();ctx.arc(wx,70,2.5,0,Math.PI*2);ctx.fillStyle="#333";ctx.fill();
  });
  // Charge level bars (like signal bars, inside car body)
  for(var i=0;i<4;i++){
    var bx=98+i*10,bh=6+i*4,by=62-bh;
    rr(ctx,bx,by,6,bh,1);
    ctx.fillStyle=i<nBars?"hsla("+hue+",70%,50%,"+(0.6*breathe)+")":"rgba(40,40,40,0.4)";
    ctx.fill();
  }
  // Value text
  if(connected){
    ctx.fillStyle=stateColor;ctx.font="700 20px system-ui,sans-serif";
    ctx.textAlign="center";ctx.textBaseline="middle";ctx.fillText(kw.toFixed(1)+" kW",75,96);
  }
  ctx.restore();
}

// ── SELF-SUFFICIENCY (150x118) — Full-size arc gauge ──
function drawSelfSuf(ctx){
  var pct=D.selfSuf,ratio=Math.min(pct/100,1),t=Date.now();
  var color=pct>=80?"#00cc66":pct>=50?"#ffaa00":"#ff4444";
  var cx=75,cy=58,R=38;
  var startA=135*(Math.PI/180);
  var sweepAngle=270*(Math.PI/180)*ratio;
  var pulseAlpha=0.7+Math.sin(t/300)*0.15;
  ctx.clearRect(0,0,150,118);
  ctx.save();ctx.translate(3.75,0);ctx.scale(0.95,0.95);
  // Label
  ctx.fillStyle="#666";ctx.font="600 8px system-ui,sans-serif";ctx.textAlign="center";ctx.letterSpacing="1.5px";
  ctx.fillText("SELF-SUFFICIENCY",cx,14);
  // Background arc
  ctx.beginPath();ctx.arc(cx,cy,R,startA,startA+270*(Math.PI/180));
  ctx.strokeStyle="#1a1a1a";ctx.lineWidth=6;ctx.lineCap="round";ctx.stroke();
  // Glow arc
  if(ratio>0){
    ctx.save();ctx.shadowColor=color;ctx.shadowBlur=4;
    ctx.beginPath();ctx.arc(cx,cy,R,startA,startA+sweepAngle);
    ctx.strokeStyle=color;ctx.lineWidth=7;ctx.lineCap="round";ctx.globalAlpha=pulseAlpha*0.3;ctx.stroke();
    ctx.globalAlpha=1;ctx.restore();
  }
  // Filled arc
  if(ratio>0){
    ctx.beginPath();ctx.arc(cx,cy,R,startA,startA+sweepAngle);
    ctx.strokeStyle=color;ctx.lineWidth=6;ctx.lineCap="round";ctx.globalAlpha=pulseAlpha;ctx.stroke();
    ctx.globalAlpha=1;
  }
  ctx.lineCap="butt";
  // % text
  ctx.fillStyle=color;ctx.font="800 22px system-ui,sans-serif";
  ctx.textAlign="center";ctx.textBaseline="middle";ctx.fillText(Math.round(pct)+"%",cx,cy-2);



  ctx.restore();
}

// ── VIRTUAL BATTERY (150x66) — Arc gauge ──
function drawVBat(ctx){
  var pct=Math.min(D.vbPct,100),ratio=pct/100,t=Date.now();
  var color=pct>=100?"#00cc66":pct>=50?"#ffaa00":"#ff4444";
  var cx=75,cy=35,R=22;
  var startA=135*(Math.PI/180);
  var sweepAngle=270*(Math.PI/180)*ratio;
  var pulseAlpha=0.7+Math.sin(t/300)*0.15;
  ctx.clearRect(0,0,150,66);
  // Label
  ctx.fillStyle="#666";ctx.font="600 7px system-ui,sans-serif";ctx.textAlign="center";
  ctx.fillText("VIRTUAL BATTERY",cx,9);
  // Background arc
  ctx.beginPath();ctx.arc(cx,cy,R,startA,startA+270*(Math.PI/180));
  ctx.strokeStyle="#1a1a1a";ctx.lineWidth=5;ctx.lineCap="round";ctx.stroke();
  // Glow arc
  if(ratio>0){
    ctx.save();ctx.shadowColor=color;ctx.shadowBlur=4;
    ctx.beginPath();ctx.arc(cx,cy,R,startA,startA+sweepAngle);
    ctx.strokeStyle=color;ctx.lineWidth=6;ctx.lineCap="round";ctx.globalAlpha=pulseAlpha*0.3;ctx.stroke();
    ctx.globalAlpha=1;ctx.restore();
  }
  // Filled arc
  if(ratio>0){
    ctx.beginPath();ctx.arc(cx,cy,R,startA,startA+sweepAngle);
    ctx.strokeStyle=color;ctx.lineWidth=5;ctx.lineCap="round";ctx.globalAlpha=pulseAlpha;ctx.stroke();
    ctx.globalAlpha=1;
  }
  ctx.lineCap="butt";
  // % text
  ctx.fillStyle=color;ctx.font="800 16px system-ui,sans-serif";
  ctx.textAlign="center";ctx.textBaseline="middle";ctx.fillText(Math.round(D.vbPct)+"%",cx,cy-2);
}

function mainLoop(){
  if(solCtx)drawSolar(solCtx);
  if(houseCtx)drawHouse(houseCtx);
  if(gridCtx)drawGrid(gridCtx);
  if(batCtx)drawBattery(batCtx);
  if(wbCtx)drawWallbox(wbCtx);
  if(ssCtx)drawSelfSuf(ssCtx);
  if(vbCtx)drawVBat(vbCtx);
  window.__pf6_id=requestAnimationFrame(mainLoop);
}
mainLoop();

